mapper.select:
SELECT 구분, 도우코드 AS 코드, Inch, Site, 0 AS 계획, SUM(ISNULL(OUT_MONTH, 0)) AS 실적, CASE WHEN 0 = 0 THEN 0 ELSE ROUND(CAST(SUM(OUT_MONTH) AS FLOAT) / 0, 4) END AS 달성률, SUM(ISNULL(BOH_MONTH, 0)) AS boh, SUM(ISNULL(IN_MONTH, 0)) AS inMonth, SUM(ISNULL(OUT_MONTH, 0)) AS outMonth, SUM(ISNULL(LOSS_MONTH, 0)) AS lossMonth, SUM(ISNULL(EOH_MONTH, 0)) AS eoh, CASE WHEN SUM(ISNULL(OUT_MONTH, 0)) = 0 THEN 0 ELSE ROUND(CAST(SUM(LOSS_MONTH) AS FLOAT) / SUM(OUT_MONTH), 4) END AS 불량률, CASE WHEN SUM(ISNULL(IN_MONTH, 0)) = 0 THEN 0 ELSE ROUND(CAST((SUM(IN_MONTH) - SUM(LOSS_MONTH)) AS FLOAT) / SUM(IN_MONTH), 4) END AS 수율 FROM V_DOI_PROD_SUBUL WHERE 1 = 1 AND SEL_CODE = 'ACTUAL'
AND YYYYMM >= #{startYyyymm}
AND YYYYMM <= #{endYyyymm}
AND SITE = #{site}
GROUP BY 구분, 구분_ord, 도우코드, Inch, Site ORDER BY 구분_ord, 도우코드, Inch

SELECT 구분, 도우코드 AS 코드, Inch, Site, -- 계획: 0으로 하드코딩 0 AS 계획, -- 실적: OUT_MONTH 사용 (ACTUAL 기준) ISNULL(OUT_MONTH, 0) AS 실적, CASE WHEN 0 = 0 THEN 0 ELSE ROUND(CAST(OUT_MONTH AS FLOAT) / 0, 4) END AS 달성률, ISNULL(BOH_MONTH, 0) AS boh, ISNULL(IN_MONTH, 0) AS inMonth, ISNULL(OUT_MONTH, 0) AS outMonth, ISNULL(LOSS_MONTH, 0) AS lossMonth, ISNULL(EOH_MONTH, 0) AS eoh, CASE WHEN ISNULL(OUT_MONTH, 0) = 0 THEN 0 ELSE ROUND(CAST(LOSS_MONTH AS FLOAT) / OUT_MONTH, 4) END AS 불량률, CASE WHEN ISNULL(IN_MONTH, 0) = 0 THEN 0 ELSE ROUND(CAST((IN_MONTH - LOSS_MONTH) AS FLOAT) / IN_MONTH, 4) END AS 수율 FROM V_DOI_PROD_SUBUL WHERE 1 = 1 AND SEL_CODE = 'ACTUAL' -- 실적 데이터만 조회
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
ORDER BY 구분_ord, 도우코드, Inch

SELECT 구분, 도우코드 AS 코드, Inch, Site, -- 1월~12월 데이터를 피벗하여 컬럼으로 표시 SUM(CASE WHEN RIGHT(YYYYMM, 2) = '01' THEN ISNULL(OUT_MONTH, 0) ELSE 0 END) AS m01, SUM(CASE WHEN RIGHT(YYYYMM, 2) = '02' THEN ISNULL(OUT_MONTH, 0) ELSE 0 END) AS m02, SUM(CASE WHEN RIGHT(YYYYMM, 2) = '03' THEN ISNULL(OUT_MONTH, 0) ELSE 0 END) AS m03, SUM(CASE WHEN RIGHT(YYYYMM, 2) = '04' THEN ISNULL(OUT_MONTH, 0) ELSE 0 END) AS m04, SUM(CASE WHEN RIGHT(YYYYMM, 2) = '05' THEN ISNULL(OUT_MONTH, 0) ELSE 0 END) AS m05, SUM(CASE WHEN RIGHT(YYYYMM, 2) = '06' THEN ISNULL(OUT_MONTH, 0) ELSE 0 END) AS m06, SUM(CASE WHEN RIGHT(YYYYMM, 2) = '07' THEN ISNULL(OUT_MONTH, 0) ELSE 0 END) AS m07, SUM(CASE WHEN RIGHT(YYYYMM, 2) = '08' THEN ISNULL(OUT_MONTH, 0) ELSE 0 END) AS m08, SUM(CASE WHEN RIGHT(YYYYMM, 2) = '09' THEN ISNULL(OUT_MONTH, 0) ELSE 0 END) AS m09, SUM(CASE WHEN RIGHT(YYYYMM, 2) = '10' THEN ISNULL(OUT_MONTH, 0) ELSE 0 END) AS m10, SUM(CASE WHEN RIGHT(YYYYMM, 2) = '11' THEN ISNULL(OUT_MONTH, 0) ELSE 0 END) AS m11, SUM(CASE WHEN RIGHT(YYYYMM, 2) = '12' THEN ISNULL(OUT_MONTH, 0) ELSE 0 END) AS m12, SUM(ISNULL(OUT_MONTH, 0)) AS total FROM V_DOI_PROD_SUBUL WHERE 1 = 1 AND SEL_CODE = 'ACTUAL' -- 실적 데이터만 조회
AND LEFT(YYYYMM, 4) = #{yyyy}
AND SITE = #{site}
GROUP BY 구분, 구분_ord, 도우코드, Inch, Site ORDER BY 구분_ord, 도우코드, Inch

SELECT TOP 500 dept_name
FROM (
    select distinct dept, dept_name from (
        select A.*, B.dept from (
        select distinct 코스트센터 dept_name from doi_dept_cost
        where 1=1

            AND YYYYMM = #{yyyymm}


            AND SITE = #{site}

        and 비용구분 = '제조'
        union
        select '제조공통' dept_name
        union
        select '카세트팀' dept_name
    ) A
    left join (
        select distinct dept, dept_name from doi_dept
        where 1=1

            AND YYYYMM = #{yyyymm}


            AND SITE = #{site}

    ) B
    on A.dept_name = B.dept_name
    ) A
)A
ORDER BY dept

SELECT TOP 500 case when 구분 = 'Z' then '합계' else 구분 end group_name , model display_name, CASE WHEN 구분 = 'Z' THEN CONCAT(구분, model, '합계') else CONCAT(구분, model) end col_name FROM ( SELECT DISTINCT 구분, model FROM ( SELECT DISTINCT 구분, 도우모델 as model FROM doi_mat_cost where 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
and not (in_qty = 0 and out_qty = 0 and loss_qty = 0) group by 구분, 도우모델 UNION SELECT 구분, model from doi_expen_matl where 1=1 and sel_code='ACTUAL'
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
and not (in_qty = 0 and out_qty = 0 and loss_qty = 0) group by 구분, model UNION SELECT 'Z' 구분, 구분 model FROM ( SELECT DISTINCT 구분 from doi_mat_cost where 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
and not (in_qty = 0 and out_qty = 0 and loss_qty = 0) group by 구분 UNION SELECT 구분 FROM doi_expen_matl where 1=1 and sel_code='ACTUAL'
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
and not (in_qty = 0 and out_qty = 0 and loss_qty = 0) group by 구분 )A ) A ) A ORDER BY CASE WHEN 구분 = 'Z' THEN 1 WHEN 구분 = '양산' THEN 2 ELSE 3 END, 구분 ,CASE WHEN model like '양산%' THEN 1 ELSE 2 END, model

SELECT DISTINCT TOP 500 도우모델 as  model from DOI_MAT_COST
where 1=1

    AND YYYYMM = #{yyyymm}


    AND SITE = #{site}


    AND SEL_CODE = #{selcode}

ORDER BY 1

SELECT TOP 500 dept_name
FROM (
    select distinct dept, dept_name from (
        select A.*, B.dept from (
        select distinct 코스트센터 dept_name from doi_dept_cost
        where 1=1

            AND YYYYMM = #{yyyymm}


            AND SITE = #{site}

        and 비용구분 = '판관'
    ) A
    left join (
        select distinct dept, dept_name from doi_dept
        where 1=1

            AND YYYYMM = #{yyyymm}


            AND SITE = #{site}

    ) B
    on A.dept_name = B.dept_name
    ) A
)A
ORDER BY dept

SELECT DISTINCT TOP 500 model
FROM (
    SELECT DISTINCT model from doi_smce_cost
    where 1=1

        AND YYYYMM = #{yyyymm}


        AND SITE = #{site}

)A
ORDER BY 1

SELECT 구분, LTRIM(RTRIM(model)) AS model, SUM(qty) AS qty FROM ( SELECT IIF(RIGHT(LTRIM(RTRIM(품번)),1)='P', N'양산', N'개발') AS 구분, LTRIM(RTRIM(품명)) AS model, ISNULL(수량,0) AS qty FROM doi_sale_resc WHERE 1=1
AND yyyymm = #{yyyymm}
AND site = #{site}
UNION ALL
SELECT IIF(RIGHT(LTRIM(RTRIM(품번)),1)='D', N'개발', N'양산') AS 구분, LTRIM(RTRIM(품명)) AS model, ISNULL(수량,0) AS qty FROM doi_invoice_resc WHERE 1=1
AND yyyymm = #{yyyymm}
AND site = #{site}
) A GROUP BY 구분, LTRIM(RTRIM(model)) ORDER BY 구분 DESC, model

SELECT SEL_CODE AS value, SEL_CODE AS text
FROM DOI_SELCODE
WHERE 1=1

    AND yyyymm = #{yyyymm}


    AND site = #{site}

ORDER BY SEL_CODE

select YYYYMM, SEL_CODE, SITE as SITE_ORG, CASE WHEN SITE='HQ' Then '본사' WHEN SITE='VN' then 'VINA' else site end as SITE, 품목자산분류, 재고자산종류, 매출원가계정, 대분류, 중분류, 소분류, 품목기타분류, 품명, 품번, 규격, 단위, 기초수량, 기초금액, 입고수량, 입고금액, 출고수량, 출고금액, 재고수량, 재고금액, CAST(재고금액 AS FLOAT)/nullif(재고수량,0) as 재고단가, 최종결산월재고단가, 구매수량, 구매금액, 기타입고수량, 기타입고금액, 판매수량, 판매원가, 투입수량, 투입금액, 기타출고수량, 기타출고금액 FROM doi_matl_resc where 1=1
and yyyymm = #{yyyymm}
and site = #{site}
order BY 품명, 품번 ;

select YYYYMM, SITE as SITE_ORG, CASE WHEN SITE='HQ' Then '본사' WHEN SITE='VN' then 'VINA' else site end as SITE, SEL_CODE, 구분, MODEL, 창고, 품번, 상계금액, 수량, 최종결산월재고단가, IN_MONTH, DIST_RATE, FINAL_AMT FROM DOI_SCOF where 1=1
and YYYYMM = #{yyyymm}
and SITE = #{site}
and SEL_CODE = #{selCode}
order BY 품번, MODEL ;

SELECT SEL_CODE AS value, SEL_CODE AS text
FROM DOI_SELCODE
WHERE 1=1

    AND yyyymm = #{yyyymm}


    AND site = #{site}

ORDER BY SEL_CODE
